#include <LittleFS.h>
#include "BitmapFont.h"

BitmapFont myFont;
lv_font_t my_lv_font;

void setup() {
    // 注册文件打开回调
    myFont.SetOpenFontFileFunction([](fs::File &fp, const String &path) -> bool {
        fp = LittleFS.open(path, "r");
        return !!fp;
    });

    // 初始化字库
    if (!myFont.Begin("/font/Bold.bin", "/font/Bold.map", 16, 16)) {
        Serial.println("字库加载失败");
        return;
    }

    // 接入 LVGL
    myFont.InitLVGLFont(&my_lv_font);

    // 创建中文标签
    lv_obj_t *label = lv_label_create(lv_scr_act());
    lv_obj_set_style_text_font(label, &my_lv_font, 0);
    lv_label_set_text(label, "你好世界");
}
